     1→import type { RequestHandler } from './$types';
     2→import { jsonResponse, errorResponse, parseRequestBody } from '$lib/server/api-utils.js';
     3→import { validateSessionType, validateRequired } from '$lib/server/validation.js';
     4→import { SessionService } from '$lib/server/sessions/session-service.js';
     5→
     6→export async function _handleGetSessions(service: SessionService, url: URL): Promise<Response> {
     7→	const containerId = url.searchParams.get('container') ?? undefined;
     8→	const sessions = await service.list(containerId);
     9→	return jsonResponse(sessions);
    10→}
    11→
    12→interface CreateSessionBody {
    13→	name?: unknown;
    14→	type?: unknown;
    15→	containerId?: unknown;
    16→}
    17→
    18→export async function _handlePostSession(
    19→	request: Request,
    20→	service: SessionService
    21→): Promise<Response> {
    22→	let body: CreateSessionBody;
    23→	try {
    24→		body = await parseRequestBody<CreateSessionBody>(request);
    25→	} catch {
    26→		return errorResponse('Request body is required', 400);
    27→	}
    28→
    29→	if (typeof body.name !== 'string') {
    30→		return errorResponse('name is required and must be a string', 400);
    31→	}
    32→	if (typeof body.type !== 'string') {
    33→		return errorResponse('type is required and must be a string', 400);
    34→	}
    35→	if (typeof body.containerId !== 'string') {
    36→		return errorResponse('containerId is required and must be a string', 400);
    37→	}
    38→
    39→	const nameValidation = validateRequired(body.name, 'name');
    40→	if (!nameValidation.success) {
    41→		return errorResponse(nameValidation.error, 400);
    42→	}
    43→
    44→	const typeValidation = validateSessionType(body.type);
    45→	if (!typeValidation.success) {
    46→		return errorResponse(typeValidation.error, 400);
    47→	}
    48→
    49→	const containerIdValidation = validateRequired(body.containerId, 'containerId');
    50→	if (!containerIdValidation.success) {
    51→		return errorResponse(containerIdValidation.error, 400);
    52→	}
    53→
    54→	try {
    55→		const session = await service.create({
    56→			name: body.name,
    57→			type: typeValidation.value,
    58→			containerId: body.containerId
    59→		});
    60→		return jsonResponse(session, 201);
    61→	} catch (err) {
    62→		const message = err instanceof Error ? err.message : 'Failed to create session';
    63→		if (message.includes('not found')) {
    64→			return errorResponse(message, 404);
    65→		}
    66→		return errorResponse(message, 500);
    67→	}
    68→}
    69→
    70→export const GET: RequestHandler = async ({ url }) => {
    71→	const { getSessionService } = await import('$lib/server/sessions/singleton.js');
    72→	return _handleGetSessions(getSessionService(), url);
    73→};
    74→
    75→export const POST: RequestHandler = async ({ request }) => {
    76→	const { getSessionService } = await import('$lib/server/sessions/singleton.js');
    77→	return _handlePostSession(request, getSessionService());
    78→};
