     6→	RemoveContainerOptions
     7→} from './docker-service.js';
     8→
     9→const HALO_NETWORK = 'halo-net';
    10→
    11→function toEnvArray(env: Record<string, string>): string[] {
    12→	return Object.entries(env).map(([k, v]) => `${k}=${v}`);
    13→}
    14→
    15→function parseBinds(mounts: string[]): string[] {
    16→	return mounts;
    17→}
    18→
    19→/**
    20→ * Real DockerService implementation using Dockerode.
    21→ * Requires access to the Docker socket at /var/run/docker.sock.
    22→ */
    23→export class DockerodeService implements DockerService {
    24→	private docker: Dockerode;
    25→
    26→	constructor(docker?: Dockerode) {
    27→		this.docker = docker ?? new Dockerode({ socketPath: '/var/run/docker.sock' });
    28→	}
    29→
    30→	async create(options: CreateContainerOptions): Promise<DockerContainerInfo> {
    31→		const container = await this.docker.createContainer({
    32→			name: options.name,
    33→			Image: options.image,
    34→			Env: options.env ? toEnvArray(options.env) : undefined,
    35→			HostConfig: {
    36→				Binds: options.mounts ? parseBinds(options.mounts) : undefined,
    37→				// Never publish ports to the host — access via halo-net only
    38→				NetworkMode: HALO_NETWORK
    39→			},
    40→			// No PortBindings — ports are accessible only within halo-net
    41→			ExposedPorts: options.ports
    42→				? Object.fromEntries(options.ports.map((p) => [`${p}/tcp`, {}]))
    43→				: undefined
    44→		});
    45→
    46→		return this.inspect(container.id);
    47→	}
    48→
    49→	async start(id: string): Promise<void> {
    50→		const container = this.docker.getContainer(id);
    51→		await container.start();
    52→	}
    53→
    54→	async stop(id: string): Promise<void> {
    55→		const container = this.docker.getContainer(id);
    56→		await container.stop();
    57→	}
    58→
    59→	async remove(id: string, options: RemoveContainerOptions = {}): Promise<void> {
    60→		const container = this.docker.getContainer(id);
    61→		await container.remove({ force: options.force ?? false });
    62→	}
    63→
    64→	async list(): Promise<DockerContainerInfo[]> {
    65→		const containers = await this.docker.listContainers({ all: true });
    66→		return containers.map((c) => ({
    67→			id: c.Id,
    68→			name: (c.Names[0] ?? '').replace(/^\//, ''),
    69→			image: c.Image,
    70→			status: c.State === 'running' ? 'running' : 'stopped',
    71→			network: HALO_NETWORK,
    72→			publishedPorts: {}
    73→		}));
    74→	}
    75→
    76→	async inspect(id: string): Promise<DockerContainerInfo> {
    77→		const container = this.docker.getContainer(id);
    78→		const info = await container.inspect();
    79→		return {
    80→			id: info.Id,
    81→			name: info.Name.replace(/^\//, ''),
    82→			image: info.Config.Image,
    83→			status: info.State.Running ? 'running' : 'stopped',
    84→			network: HALO_NETWORK,
    85→			publishedPorts: {}
    86→		};
    87→	}
    88→}
