    26→		if (applied.has(file)) continue;
    27→
    28→		const sql = readFileSync(join(MIGRATIONS_DIR, file), 'utf-8');
    29→
    30→		db.transaction(() => {
    31→			db.exec(sql);
    32→			db.prepare('INSERT INTO _migrations (filename) VALUES (?)').run(file);
    33→		})();
    34→	}
    35→}
