     1→import { writable } from 'svelte/store';
     2→import type { FeedEntry } from '$lib/types/feed.js';
     3→
     4→export interface StreamState {
     5→	entries: FeedEntry[];
     6→	connected: boolean;
     7→	error: string | null;
     8→}
     9→
    10→export interface SessionStream {
    11→	subscribe: (run: (value: StreamState) => void) => () => void;
    12→	destroy: () => void;
    13→}
    14→
    15→export function createSessionStream(sessionId: string): SessionStream {
    16→	const { subscribe, update } = writable<StreamState>({
    17→		entries: [],
    18→		connected: false,
    19→		error: null
    20→	});
    21→
    22→	let es: EventSource | null = null;
    23→	let retryTimeout: ReturnType<typeof setTimeout> | null = null;
    24→	let retryDelay = 1000;
    25→	let destroyed = false;
    26→
    27→	function connect(): void {
    28→		es = new EventSource(`/api/sessions/${sessionId}/stream`);
    29→
    30→		es.onopen = (): void => {
    31→			retryDelay = 1000;
    32→			update((s) => ({ ...s, connected: true, error: null }));
    33→		};
    34→
    35→		es.onmessage = (event: MessageEvent): void => {
    36→			const entry = JSON.parse(event.data as string) as FeedEntry;
    37→			update((s) => ({ ...s, entries: [...s.entries, entry] }));
    38→		};
    39→
    40→		es.onerror = (): void => {
    41→			es?.close();
    42→			es = null;
    43→			update((s) => ({ ...s, connected: false }));
    44→			if (!destroyed) {
    45→				retryTimeout = setTimeout((): void => {
    46→					retryDelay = Math.min(retryDelay * 2, 30000);
    47→					connect();
    48→				}, retryDelay);
    49→			}
    50→		};
    51→	}
    52→
    53→	connect();
    54→
    55→	return {
    56→		subscribe,
    57→		destroy(): void {
    58→			destroyed = true;
    59→			if (retryTimeout !== null) {
    60→				clearTimeout(retryTimeout);
    61→				retryTimeout = null;
    62→			}
    63→			es?.close();
    64→			es = null;
    65→		}
    66→	};
    67→}
