     6→// Exported for testing (underscore prefix required by SvelteKit for custom route exports)
     7→export async function _handleGetContainer(
     8→	id: string,
     9→	service: ContainerService
    10→): Promise<Response> {
    11→	const container = await service.get(id);
    12→	if (!container) {
    13→		return errorResponse(`Container '${id}' not found`, 404);
    14→	}
    15→	return jsonResponse(container);
    16→}
    17→
    18→interface PatchContainerBody {
    19→	config?: unknown;
    20→}
    21→
    22→export async function _handlePatchContainer(
    23→	id: string,
    24→	request: Request,
    25→	service: ContainerService
    26→): Promise<Response> {
    27→	let body: PatchContainerBody;
    28→	try {
    29→		body = await parseRequestBody<PatchContainerBody>(request);
    30→	} catch {
    31→		return errorResponse('Request body is required', 400);
    32→	}
    33→
    34→	const existing = await service.get(id);
    35→	if (!existing) {
    36→		return errorResponse(`Container '${id}' not found`, 404);
    37→	}
    38→
    39→	const config = (body.config ?? {}) as Partial<ContainerConfig>;
    40→	const updated = await service.updateConfig(id, config);
    41→	return jsonResponse(updated);
    42→}
    43→
    44→export async function _handleDeleteContainer(
    45→	id: string,
    46→	service: ContainerService
    47→): Promise<Response> {
    48→	const existing = await service.get(id);
    49→	if (!existing) {
    50→		return errorResponse(`Container '${id}' not found`, 404);
    51→	}
    52→
    53→	await service.destroy(id);
    54→	return new Response(null, { status: 204 });
    55→}
