     1→import type { SessionType } from '$lib/types/session.js';
     2→
     3→type ValidationSuccess<T> = { success: true; value: T };
     4→type ValidationFailure = { success: false; error: string };
     5→type ValidationResult<T> = ValidationSuccess<T> | ValidationFailure;
     6→
     7→export function validateContainerName(name: string): ValidationResult<string> {
     8→	if (name.length < 3) {
     9→		return { success: false, error: 'Container name must be at least 3 characters' };
    10→	}
    11→	if (name.length > 63) {
    12→		return { success: false, error: 'Container name must be at most 63 characters' };
    13→	}
    14→	if (!/^[a-zA-Z0-9-]+$/.test(name)) {
    15→		return {
    16→			success: false,
    17→			error: 'Container name may only contain alphanumeric characters and hyphens'
    18→		};
    19→	}
    20→	return { success: true, value: name };
    21→}
    22→
    23→const VALID_SESSION_TYPES: SessionType[] = ['claude', 'terminal', 'shell'];
    24→
    25→export function validateSessionType(type: string): ValidationResult<SessionType> {
    26→	if ((VALID_SESSION_TYPES as string[]).includes(type)) {
    27→		return { success: true, value: type as SessionType };
    28→	}
    29→	return {
    30→		success: false,
    31→		error: `Session type must be one of: ${VALID_SESSION_TYPES.join(', ')}`
    32→	};
    33→}
    34→
    35→export function validateRequired(value: string, fieldName: string): ValidationResult<string> {
    36→	if (value.trim().length === 0) {
    37→		return { success: false, error: `${fieldName} is required` };
    38→	}
    39→	return { success: true, value };
    40→}
